function usage() {
  return `Usage: node scripts/build-generated.mjs [--check] [--list-outputs]

Build committed generated runtime outputs from canonical TypeScript sources.

Options:
  --check   Compare generated output with committed files without writing.
  --list-outputs
            Print generated output paths, one per line.
  --help    Show this help.
`;
}

function parseArgs(argv) {
  const options = { check: false, help: false, listOutputs: false };

  for (const arg of argv) {
    if (arg === '--check') {
      options.check = true;
    } else if (arg === '--list-outputs') {
      options.listOutputs = true;
    } else if (arg === '--help' || arg === '-h') {
      options.help = true;
    } else {
      throw new Error(`Unknown argument: ${arg}`);
    }
  }

  if (options.check && options.listOutputs) {
    throw new Error('Use only one of --check or --list-outputs');
  }

  return options;
}

async function readIfExists(filePath) {
  try {
    return await readFile(filePath, 'utf8');
  } catch (error) {
    if (error && error.code === 'ENOENT') return null;
    throw error;
  }
}

function bannerFor(mapping) {
  return `${GENERATED_BANNER_PREFIX}
// Source: ${mapping.source}`;
}

function replacementFor(specifier) {
  return `'${specifier}'`;
}

export function rewriteImportSpecifiers(text, rewrite, mappingId) {
  const sourceFile = ts.createSourceFile(
    `${mappingId}.mjs`,
    text,
    ts.ScriptTarget.Latest,
    true,
    ts.ScriptKind.JS,
  );
  const replacements = [];

  function addModuleSpecifier(moduleSpecifier) {
    if (!ts.isStringLiteral(moduleSpecifier)) return;
    if (moduleSpecifier.text !== rewrite.from) return;

    replacements.push({
      start: moduleSpecifier.getStart(sourceFile),
      end: moduleSpecifier.getEnd(),
      text: replacementFor(rewrite.to),
    });
  }

  function visit(node) {
    if (ts.isImportDeclaration(node)) {
      addModuleSpecifier(node.moduleSpecifier);
    } else if (ts.isExportDeclaration(node) && node.moduleSpecifier) {
      addModuleSpecifier(node.moduleSpecifier);
    } else if (
      ts.isCallExpression(node) &&
      node.expression.kind === ts.SyntaxKind.ImportKeyword &&
      node.arguments.length > 0
    ) {
      addModuleSpecifier(node.arguments[0]);
    }

    ts.forEachChild(node, visit);
  }

  visit(sourceFile);

  if (replacements.length === 0) {
    throw new Error(
      `Import rewrite for ${mappingId} expected emitted output to contain module specifier ${rewrite.from}`,
    );
  }

  let rewritten = text;
  for (const replacement of replacements.toSorted(
    (a, b) => b.start - a.start,
  )) {
    rewritten =
      rewritten.slice(0, replacement.start) +
      replacement.text +
      rewritten.slice(replacement.end);
  }

  return rewritten;
}

async function buildMapping(mapping) {
  const sourcePath = path.join(repoRoot, mapping.source);
  const outputPath = path.join(repoRoot, mapping.output);
  const source = await readIfExists(sourcePath);

  if (source === null && mapping.pendingUntilSourceExists) {
    return {
      mapping,
      status: 'pending',
      message: `${mapping.source} does not exist yet`,
    };
  }

  if (source === null) {
    throw new Error(`Missing generated-output source: ${mapping.source}`);
  }

  const result = await build({
    entryPoints: [sourcePath],
    outfile: outputPath,
    bundle: mapping.bundle ?? false,
    platform: 'node',
    format: 'esm',
    target: 'node22',
    write: false,
    legalComments: 'none',
    logLevel: 'silent',
    banner: {
      js: bannerFor(mapping),
    },
  });

  const outputFile = result.outputFiles?.[0];
  if (!outputFile) {
    throw new Error(`No generated output emitted for ${mapping.id}`);
  }

  let text = outputFile.text;
  for (const rewrite of mapping.importRewrites ?? []) {
    text = rewriteImportSpecifiers(text, rewrite, mapping.id);
  }

  return {
    mapping,
    status: 'built',
    outputPath,
    text,
  };
}

function firstDifference(actual, expected) {
  const max = Math.min(actual.length, expected.length);
  for (let index = 0; index < max; index += 1) {
    if (actual[index] !== expected[index]) return index;
  }
  return actual.length === expected.length ? -1 : max;
}

async function checkGenerated() {
  const failures = [];

  for (const mapping of generatedOutputs) {
    const result = await buildMapping(mapping);
    if (result.status === 'pending') {
      console.log(`${mapping.id}: pending (${result.message})`);
      continue;
    }

    const committed = await readIfExists(result.outputPath);
    if (committed === null) {
      failures.push(`${mapping.output}: missing generated output`);
      continue;
    }

    if (committed !== result.text) {
      const offset = firstDifference(committed, result.text);
      failures.push(
        `${mapping.output}: generated output is stale (first byte difference at ${offset})`,
      );
      continue;
    }

    console.log(`${mapping.id}: in sync`);
  }

  if (failures.length > 0) {
    throw new Error(`Generated output drift detected:\n${failures.join('\n')}`);
  }
}

async function writeGenerated() {
  for (const mapping of generatedOutputs) {
    const result = await buildMapping(mapping);
    if (result.status === 'pending') {
      console.log(`${mapping.id}: pending (${result.message})`);
      continue;
    }

    await mkdir(path.dirname(result.outputPath), { recursive: true });
    await writeFile(result.outputPath, result.text);
    console.log(`${mapping.id}: wrote ${mapping.output}`);
  }
}

async function main() {
  const options = parseArgs(process.argv.slice(2));
  if (options.help) {
    process.stdout.write(usage());
    return;
  }

  if (options.listOutputs) {
    process.stdout.write(
      generatedOutputs.map((mapping) => mapping.output).join('\n') + '\n',
    );
  } else if (options.check) {
    await checkGenerated();
  } else {
    await writeGenerated();
  }
}

if (
  process.argv[1] &&
  path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)
) {
  main().catch((error) => {
    console.error(error.message);
    process.exitCode = 1;
  });
}
